const LIBM: u64 = 4;
const LIBM_WIDE: u64 = 16;

// ---------------------------------------------------------------------------
// Fixture loading + JSON helpers
// ---------------------------------------------------------------------------

fn load_fixture() -> Value {
    let path =
        PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("tests/fixtures/jax_core_reference.json");
    let text = fs::read_to_string(&path)
        .unwrap_or_else(|e| panic!("could not read {}: {}", path.display(), e));
    serde_json::from_str(&text).expect("fixture JSON parse")
}

fn f(v: &Value) -> f64 {
    v.as_f64().expect("expected f64")
}
fn vec_f(v: &Value) -> Vec<f64> {
    v.as_array().expect("array").iter().map(f).collect()
}
fn vec_b(v: &Value) -> Vec<bool> {
    v.as_array()
        .expect("array")
        .iter()
        .map(|e| e.as_bool().expect("expected bool"))
        .collect()
}
fn mat_f(v: &Value) -> Vec<Vec<f64>> {
    v.as_array().expect("array").iter().map(vec_f).collect()
}

fn parse_layers(v: &Value) -> Vec<MlpLayer> {
    v.as_array()
        .expect("layers array")
        .iter()
        .map(|layer| MlpLayer {
            w: mat_f(&layer["w"]),
            b: vec_f(&layer["b"]),
        })
        .collect()
}

fn parse_activation(v: &Value) -> Activation {
    match v.as_str().expect("activation string") {
        "tanh" => Activation::Tanh,
        "relu" => Activation::Relu,
        other => panic!("unsupported activation: {other}"),
    }
}

// ---------------------------------------------------------------------------
// ULP comparison
// ---------------------------------------------------------------------------

/// Count ULPs between two f64 values. Returns `u64::MAX` for non-finite
/// or different-sign values (which always fail any finite tolerance).
fn ulps_between(a: f64, b: f64) -> u64 {
    if a == b {
        return 0;
    }
    if !a.is_finite() || !b.is_finite() {
        return u64::MAX;
    }
    if a.is_sign_negative() != b.is_sign_negative() {
        return u64::MAX;
    }
    a.to_bits().abs_diff(b.to_bits())
}

#[track_caller]
fn assert_close(actual: f64, expected: f64, tol_ulps: u64, label: &str) {
    if actual == expected {
        return;
    }
    let ulps = ulps_between(actual, expected);
    assert!(
        ulps <= tol_ulps,
        "{label}: actual={actual} expected={expected} differs by {ulps} ULPs (budget {tol_ulps})",
    );
}

// ---------------------------------------------------------------------------
// Fixture coverage guard — fails loudly if the emitter drops a primitive.
// ---------------------------------------------------------------------------

#[test]
fn fixture_covers_all_expected_primitives() {
    let fixture = load_fixture();
    let obj = fixture.as_object().expect("top-level object");
    let expected = [
        // session 2 — jax_core.py → math.rs (12 primitives)
        "tangent_flow_substrate",
        "banach_state",
        "tangent_flow_canonical",
        "lookup_squared_distance",
        "tangent_flow_canonical_inverse",
        "tangent_flow_inversion_residual",
        "laplace_covariance_from_jacobian",
        "laplace_covariance_from_hessian",
        "caputo_flow",
        "mlp_forward",
        "learned_field_substrate",
        "laplace_log_evidence",
        // session 4 — gfdr_model.py → gfdr_model.rs (6)
        "gfdr_alpha_s",
        "gfdr_plateau_height",
        "gfdr_vertex_regime",
        "gfdr_generate_locus",
        "gfdr_interp_locus",
        "gfdr_locus_residual",
        // session 4 — sidecar.py → sidecar.rs (1)
        "sidecar_round_key",
        // session 4 — flow.py → flow.rs (1)
        "flow",
        // session 6 — intent algebra (operations.py → operations.rs).
        // Schema parity, not bit-identity — see the dedicated test
        // below for the Python→Rust JSON parity contract.
        "sacrifice_record",
        // session 7 — provenance + wrapped-variant wire parity.
        // `provenance_hash` is bit-identity (4-byte blake2b digest must
        // match exactly); `operation_output_regime_at` is schema parity
        // (structured fields; timestamps + notes excluded — see the
        // section header in `emit_jax_core_reference.py` and the notes
        // asymmetry note in CLAUDE.md).
        "provenance_hash",
        "operation_output_regime_at",
        // session 7 followup — sidecar wire-format lock-in. Full JSON
        // round-trip parity per docs/SIDECAR_FORMAT.md v1.0.
        "sidecar_wire_format",
        // session 8 — posterior surface.
        // `tangent_flow_forward_jacobian` is per-primitive bit-identity
        // (category 1); the Rust port encodes the diagonal Jacobian
        // analytically while Python uses jax.jacfwd. Same single libm
        // pow call → LIBM tolerance.
        // `operation_output_posterior` is schema parity (category 2) for
        // the wrapped posterior variant — same template as session 7's
        // `operation_output_regime_at`, extended with the Posterior
        // value-struct contents (mean / covariance / log_evidence /
        // modes / notes).
        "tangent_flow_forward_jacobian",
        "operation_output_posterior",
    ];
    assert_eq!(
        obj.len(),
        expected.len(),
        "fixture has {} primitives, expected {}",
        obj.len(),
        expected.len()
    );
    for name in expected {
        assert!(obj.contains_key(name), "fixture missing primitive: {name}");
    }
}

