#[test]
fn jax_core_lookup_squared_distance() {
    let fixture = load_fixture();
    for (i, case) in fixture["lookup_squared_distance"]
        .as_array()
        .unwrap()
        .iter()
        .enumerate()
    {
        let inp = &case["inputs"];
        let exp = &case["outputs"];
        let chits = vec_f(&inp["field_chits"]);
        let gammas = vec_f(&inp["field_gammas"]);
        let taus = vec_f(&inp["field_taus"]);
        let has_tau = vec_b(&inp["has_tau"]);
        let d = lookup_squared_distance(
            f(&inp["query_chit"]),
            f(&inp["query_gamma"]),
            &chits,
            &gammas,
            &taus,
            &has_tau,
            f(&inp["tau_obs"]),
            f(&inp["tau_obs_weight"]),
        );
        let expected = vec_f(&exp["d2"]);
        assert_eq!(
            d.len(),
            expected.len(),
            "lookup_squared_distance[{i}] length mismatch"
        );
        for (k, (got, want)) in d.iter().zip(expected.iter()).enumerate() {
            assert_close(
                *got,
                *want,
                LIBM,
                &format!("lookup_squared_distance[{i}][{k}]"),
            );
        }
    }
}

