fn parse_dispatch_path(s: &str) -> DispatchPath {
    match s {
        "direct_compute" => DispatchPath::DirectCompute,
        "table_hit" => DispatchPath::TableHit,
        "compute_fallback" => DispatchPath::ComputeFallback,
        other => panic!("unknown dispatch_path: {other}"),
    }
}

fn regime_label_str(label: RegimeLabel) -> &'static str {
    match label {
        RegimeLabel::DeepC => "deep_c",
        RegimeLabel::CNearS => "c_near_s",
        RegimeLabel::SCritical => "s_critical",
        RegimeLabel::RNearS => "r_near_s",
        RegimeLabel::DeepR => "deep_r",
    }
}

/// Cross-language bit-identity for `provenance_hash`.
///
/// The contract is on the **raw 4-byte blake2b digest**, not the
/// float view: the digest is bit-stable and serializes losslessly as
/// hex, while the `n / 2^32` float view cannot round-trip through
/// JSON's decimal-string representation under naive parsers (1-ULP
/// drift on some bit patterns; rational hash → no tolerance budget).
/// Comparing digests sidesteps the wire-format risk entirely.
///
/// Any drift in the
/// `(solver_version | operation | dispatch_path | table_version)`
/// payload encoding breaks the EXR-channel provenance fingerprint
/// contract.
#[test]
fn provenance_hash_python_to_rust_parity() {
    let fixture = load_fixture();
    let cases = fixture["provenance_hash"]
        .as_array()
        .expect("provenance_hash array");
    assert!(!cases.is_empty(), "provenance_hash fixture must be non-empty");

    for (i, case) in cases.iter().enumerate() {
        let inputs = &case["inputs"];
        let op = inputs["operation"].as_str().expect("operation str");
        let dp_str = inputs["dispatch_path"].as_str().expect("dispatch_path str");
        let dp = parse_dispatch_path(dp_str);
        let tv = inputs["table_version"].as_str().map(|s| s.to_string());
        let expected_hex = case["output_bits_hex"]
            .as_str()
            .expect("output_bits_hex str");

        let prov = make_provenance(op, dp, tv.clone(), Vec::new());
        let actual_bytes = provenance_digest_bytes(&prov);
        let actual_hex = actual_bytes
            .iter()
            .map(|b| format!("{b:02x}"))
            .collect::<String>();

        assert_eq!(
            actual_hex, expected_hex,
            "provenance_hash[{i}] ({op}, {dp_str}, {tv:?}): \
             digest hex mismatch",
        );
    }

    // Coverage: every dispatch path should appear at least once, and at
    // least one table_version=null + at least one table_version=string.
    let mut dps: BTreeMap<String, bool> = BTreeMap::new();
    let mut has_null_tv = false;
    let mut has_str_tv = false;
    for case in cases {
        let dp = case["inputs"]["dispatch_path"].as_str().unwrap();
        dps.insert(dp.to_string(), true);
        if case["inputs"]["table_version"].is_null() {
            has_null_tv = true;
        } else {
            has_str_tv = true;
        }
    }
    for required in ["direct_compute", "table_hit", "compute_fallback"] {
        assert!(
            dps.contains_key(required),
            "provenance_hash fixture missing dispatch_path={required}",
        );
    }
    assert!(has_null_tv, "fixture missing a null table_version case");
    assert!(has_str_tv, "fixture missing a non-null table_version case");
}

/// Cross-language wire parity for `OperationOutput<RegimeReading>`.
///
/// Structured-field equality only: timestamps are non-deterministic
/// (Python uses `time.monotonic_ns()`, Rust uses `Instant`-elapsed),
/// and the notes diagnostic strings have a float-formatting divergence
/// (`f"{0.0}"` is `"0.0"` in Python, `format!("{}", 0.0)` is `"0"` in
/// Rust — see CLAUDE.md asymmetry note). Both exclusions are by design;
/// the load-bearing contract is the structured flags and the provenance
/// hash inputs.
#[test]
fn operation_output_regime_at_python_to_rust_parity() {
    let fixture = load_fixture();
    let cases = fixture["operation_output_regime_at"]
        .as_array()
        .expect("operation_output_regime_at array");
    assert!(
        !cases.is_empty(),
        "operation_output_regime_at fixture must be non-empty",
    );

    for case in cases {
        let label = case["label"].as_str().unwrap_or("<unlabeled>");
        let inputs = &case["inputs"];
        let canonical = CanonicalState {
            chit: inputs["chit"].as_f64().expect("chit"),
            gamma_AB: inputs["gamma_AB"].as_f64().expect("gamma_AB"),
            k_frust: inputs["k_frust"].as_bool().expect("k_frust"),
        };
        let tau_obs = inputs["tau_obs"].as_f64().expect("tau_obs");

        let out = regime_at_wrapped(&canonical, tau_obs);
        let expected = &case["output"];

        // value: regime label string + k_frust bool
        let py_regime = expected["value"]["regime"].as_str().unwrap();
        assert_eq!(
            regime_label_str(out.value.regime),
            py_regime,
            "{label}: value.regime",
        );
        assert_eq!(
            out.value.k_frust,
            expected["value"]["k_frust"].as_bool().unwrap(),
            "{label}: value.k_frust",
        );

        // validation: three structured flags. Notes excluded per the
        // documented float-formatting asymmetry above.
        assert_eq!(
            out.validation.asymptotic_closure_compliant,
            expected["validation"]["asymptotic_closure_compliant"]
                .as_bool()
                .unwrap(),
            "{label}: asymptotic_closure_compliant",
        );
        assert_eq!(
            out.validation.k_frust_invariant,
            expected["validation"]["k_frust_invariant"].as_bool().unwrap(),
            "{label}: k_frust_invariant",
        );
        let py_rt = &expected["validation"]["round_trip_residual"];
        match (out.validation.round_trip_residual, py_rt) {
            (None, v) if v.is_null() => (),
            (Some(actual), v) if v.is_f64() => {
                // Tolerance, not bit-equality: `round_trip_residual` is
                // a computed L2 norm (forward-then-back via the
                // translation field), so the cross-language contract
                // is convergence to the same value, not bit-identity.
                // Going through JSON's decimal-string form drops up to
                // 1 ULP under naive parsers anyway. LIBM_WIDE absorbs
                // both the wire-format drift and the libm reduction-
                // order difference.
                assert_close(
                    actual,
                    v.as_f64().unwrap(),
                    LIBM_WIDE,
                    &format!("{label}: round_trip_residual"),
                );
            }
            other => panic!(
                "{label}: round_trip_residual mismatch — Rust {:?}, Python {py_rt}",
                other.0,
            ),
        }

        // provenance: solver_version + operation + dispatch_path + table_version.
        // timestamp_ns excluded (non-deterministic; both impls are monotonic
        // but the reference epoch is process-local on each side).
        assert_eq!(
            out.provenance.solver_version,
            expected["provenance"]["solver_version"].as_str().unwrap(),
            "{label}: solver_version",
        );
        assert_eq!(
            out.provenance.solver_version, SOLVER_VERSION,
            "{label}: Rust SOLVER_VERSION must equal Python __version__",
        );
        assert_eq!(
            out.provenance.operation,
            expected["provenance"]["operation"].as_str().unwrap(),
            "{label}: operation",
        );
        assert_eq!(
            out.provenance.dispatch_path,
            parse_dispatch_path(
                expected["provenance"]["dispatch_path"].as_str().unwrap()
            ),
            "{label}: dispatch_path",
        );
        let py_tv = expected["provenance"]["table_version"].as_str();
        assert_eq!(
            out.provenance.table_version.as_deref(),
            py_tv,
            "{label}: table_version",
        );
    }
}

// ---------------------------------------------------------------------------
// Session 8 — operation_output_posterior wrapped-variant wire parity
// ---------------------------------------------------------------------------

/// Cross-language schema parity for
/// `forward_sweep_invert_posterior_wrapped` — Session 8 extension of
/// session 7's `operation_output_regime_at` template.
///
/// Each fixture case reconstructs the field shape from the `label`
/// (four cases: tangent_flow_identity, tangent_flow_nonidentity,
/// lookup_table_top_k_5, lookup_table_k_eq_1), calls the Rust wrapped
/// op with the same inputs, and asserts:
///
///   * Posterior.mean.{chit, gamma_AB} via LIBM_WIDE ULP tolerance
///     (computed floats per fixture-discipline rule); k_frust bit-exact.
///   * Posterior.covariance via LIBM_WIDE on each of the 4 cells.
///   * Posterior.noise_variance bit-exact (input echo).
///   * Posterior.log_evidence: tolerated when Some, bit-exact null vs
///     bit-exact null otherwise.
///   * Posterior.modes count + per-element fields (LIBM_WIDE on floats).
///   * Posterior.notes bit-exact (the only float-formatted token would
///     be top_k, an integer — no Python/Rust `f"{0.0}"` vs `format!`
///     divergence).
///   * ValidationReport flags + round_trip_residual.
///   * Provenance solver_version, operation, dispatch_path,
///     table_version. timestamps + notes excluded (same documented
///     asymmetry as the regime_at parity test).
#[test]
fn operation_output_posterior_python_to_rust_parity() {
    let fixture = load_fixture();
    let cases = fixture["operation_output_posterior"]
        .as_array()
        .expect("operation_output_posterior array");
    assert!(
        !cases.is_empty(),
        "operation_output_posterior fixture must be non-empty",
    );

    for case in cases {
        let label = case["label"].as_str().unwrap_or("<unlabeled>");
        let inputs = &case["inputs"];
        let tau_obs = inputs["tau_obs"].as_f64().expect("tau_obs");
        let noise_variance = inputs["noise_variance"].as_f64().expect("noise_variance");
        let top_k = inputs["top_k"].as_u64().expect("top_k") as usize;
        let s_chit = inputs["s_chit"].as_f64().expect("s_chit");
        let s_gamma_AB = inputs["s_gamma_AB"].as_f64().expect("s_gamma_AB");

        let target = posterior_substrate(s_chit, s_gamma_AB, tau_obs);
        let (field, grid_opt) = build_posterior_field(label);
        let out = forward_sweep_invert_posterior_wrapped(
            &target,
            &field,
            tau_obs,
            grid_opt.as_deref(),
            noise_variance,
            false,
            None,
            top_k,
        )
        .unwrap_or_else(|e| panic!("{label}: wrapped posterior errored: {e:?}"));

        let expected = &case["output"];
        let py_value = &expected["value"];

        // value.mean
        let py_mean = &py_value["mean"];
        assert_close(
            out.value.mean.chit,
            py_mean["chit"].as_f64().unwrap(),
            LIBM_WIDE,
            &format!("{label}: mean.chit"),
        );
        assert_close(
            out.value.mean.gamma_AB,
            py_mean["gamma_AB"].as_f64().unwrap(),
            LIBM_WIDE,
            &format!("{label}: mean.gamma_AB"),
        );
        assert_eq!(
            out.value.mean.k_frust,
            py_mean["k_frust"].as_bool().unwrap(),
            "{label}: mean.k_frust",
        );

        // value.covariance — LIBM_WIDE per cell.
        let py_cov = mat_f(&py_value["covariance"]);
        for i in 0..2 {
            for j in 0..2 {
                assert_close(
                    out.value.covariance[i][j],
                    py_cov[i][j],
                    LIBM_WIDE,
                    &format!("{label}: covariance[{i}][{j}]"),
                );
            }
        }

        // value.noise_variance — input echo, bit-exact.
        assert_eq!(
            out.value.noise_variance.to_bits(),
            py_value["noise_variance"].as_f64().unwrap().to_bits(),
            "{label}: noise_variance",
        );

        // value.log_evidence — Option<f64>; tolerated when Some.
        let py_le = &py_value["log_evidence"];
        match (out.value.log_evidence, py_le) {
            (None, v) if v.is_null() => (),
            (Some(actual), v) if v.is_f64() => {
                assert_close(
                    actual,
                    v.as_f64().unwrap(),
                    LIBM_WIDE,
                    &format!("{label}: log_evidence"),
                );
            }
            other => panic!(
                "{label}: log_evidence mismatch — Rust {:?}, Python {py_le}",
                other.0,
            ),
        }

        // value.modes — count + element fields. Python's emit-condition is
        // tuple-equality on f64 (bit-exact); Rust mirrors via to_bits()
        // comparison. Both impls evaluate the same numerical inputs, so
        // the emit decision agrees.
        let py_modes = py_value["modes"].as_array().expect("modes array");
        assert_eq!(
            out.value.modes.len(),
            py_modes.len(),
            "{label}: modes.len",
        );
        for (i, (rust_mode, py_mode)) in out.value.modes.iter().zip(py_modes).enumerate() {
            assert_close(
                rust_mode.chit,
                py_mode["chit"].as_f64().unwrap(),
                LIBM_WIDE,
                &format!("{label}: modes[{i}].chit"),
            );
            assert_close(
                rust_mode.gamma_AB,
                py_mode["gamma_AB"].as_f64().unwrap(),
                LIBM_WIDE,
                &format!("{label}: modes[{i}].gamma_AB"),
            );
            assert_eq!(
                rust_mode.k_frust,
                py_mode["k_frust"].as_bool().unwrap(),
                "{label}: modes[{i}].k_frust",
            );
        }

        // value.notes — bit-exact (no float-format divergence in these strings).
        let py_notes = py_value["notes"]
            .as_array()
            .expect("notes array")
            .iter()
            .map(|v| v.as_str().unwrap().to_string())
            .collect::<Vec<_>>();
        assert_eq!(out.value.notes, py_notes, "{label}: notes");

        // validation flags + round_trip_residual (matches regime_at parity).
        assert_eq!(
            out.validation.asymptotic_closure_compliant,
            expected["validation"]["asymptotic_closure_compliant"]
                .as_bool()
                .unwrap(),
            "{label}: asymptotic_closure_compliant",
        );
        assert_eq!(
            out.validation.k_frust_invariant,
            expected["validation"]["k_frust_invariant"].as_bool().unwrap(),
            "{label}: k_frust_invariant",
        );
        let py_rt = &expected["validation"]["round_trip_residual"];
        assert!(
            py_rt.is_null() && out.validation.round_trip_residual.is_none(),
            "{label}: posterior wrapped variant always emits None round_trip_residual",
        );

        // provenance fields (timestamps + notes excluded).
        assert_eq!(
            out.provenance.solver_version,
            expected["provenance"]["solver_version"].as_str().unwrap(),
            "{label}: solver_version",
        );
        assert_eq!(
            out.provenance.solver_version, SOLVER_VERSION,
            "{label}: Rust SOLVER_VERSION must equal Python __version__",
        );
        assert_eq!(
            out.provenance.operation,
            expected["provenance"]["operation"].as_str().unwrap(),
            "{label}: operation",
        );
        assert_eq!(
            out.provenance.dispatch_path,
            parse_dispatch_path(
                expected["provenance"]["dispatch_path"].as_str().unwrap()
            ),
            "{label}: dispatch_path",
        );
        let py_tv = expected["provenance"]["table_version"].as_str();
        assert_eq!(
            out.provenance.table_version.as_deref(),
            py_tv,
            "{label}: table_version",
        );
    }
}

fn posterior_substrate(s_chit: f64, s_gamma_AB: f64, tau_obs: f64) -> SubstrateState {
    let mut observables: BTreeMap<String, f64> = BTreeMap::new();
    observables.insert("substrate_chit".to_string(), s_chit);
    observables.insert("substrate_gamma_AB".to_string(), s_gamma_AB);
    SubstrateState {
        tau_obs,
        label: None,
        axes: BTreeMap::new(),
        observables,
    }
}

fn build_posterior_field(label: &str) -> (TranslationField, Option<Vec<[f64; 2]>>) {
    let origin = TranslationRule {
        operating_point: OperatingPoint {
            label: "origin".to_string(),
            gt: Gt::S,
            axes: BTreeMap::new(),
        },
        xdot_choice: "default".to_string(),
        canonical: CanonicalPoint {
            chit: 0.0,
            gamma_AB: 0.0,
            k_frust: false,
            method: "test".to_string(),
            extras: BTreeMap::new(),
        },
    };
    let lookup_rule = |label: &str, chit: f64, gamma_AB: f64| TranslationRule {
        operating_point: OperatingPoint {
            label: label.to_string(),
            gt: Gt::S,
            axes: {
                let mut m: BTreeMap<String, Value> = BTreeMap::new();
                m.insert("tau_obs".to_string(), Value::from(1.0));
                m
            },
        },
        xdot_choice: "default".to_string(),
        canonical: CanonicalPoint {
            chit,
            gamma_AB,
            k_frust: false,
            method: "test".to_string(),
            extras: BTreeMap::new(),
        },
    };
    match label {
        "tangent_flow_identity" => (
            TranslationField::TangentFlow(TangentFlowField {
                direction: Direction::Forward,
                rule_at_origin: origin,
                scaling: ScalingRule {
                    tau_obs_ref: 1.0,
                    delta_gamma: 0.0,
                    delta_chit: 0.0,
                    refinement: None,
                },
                description: None,
            }),
            None,
        ),
        "tangent_flow_nonidentity" => (
            TranslationField::TangentFlow(TangentFlowField {
                direction: Direction::Forward,
                rule_at_origin: origin,
                scaling: ScalingRule {
                    tau_obs_ref: 1.0,
                    delta_gamma: 0.5,
                    delta_chit: 0.3,
                    refinement: None,
                },
                description: None,
            }),
            None,
        ),
        "lookup_table_top_k_5" | "lookup_table_k_eq_1" => (
            TranslationField::LookupTable(LookupTableField {
                direction: Direction::Forward,
                rule: vec![
                    lookup_rule("a", 0.5, -0.3),
                    lookup_rule("b", 0.8, 0.2),
                    lookup_rule("c", -0.4, 0.4),
                ],
                description: None,
            }),
            Some(vec![[0.5, -0.3], [0.8, 0.2], [-0.4, 0.4]]),
        ),
        other => panic!("unknown posterior parity label: {other}"),
    }
}

// ---------------------------------------------------------------------------
// Session 7 followup — sidecar JSON wire-format parity (SIDECAR_FORMAT.md v1.0)
// ---------------------------------------------------------------------------

/// End-to-end cross-language parity for `InverseLookupSidecar`.
///
/// Python builds a small Banach sidecar via the v1 reference producer
/// (`BanachSubstrate.build_sidecar`), encodes it to JSON via
/// `encode_sidecar_to_json` (the spec-conformant serializer), and emits
/// the result as the `sidecar_wire_format` fixture entry. This test
/// deserializes the same JSON via serde and asserts:
///
/// 1. Structural metadata round-trips (wire_version, version,
///    driver_profile_id, rounding_decimals, grid lengths).
/// 2. Every `(canonical, tau)` from the canonical_grid hits via
///    `lookup_forward` and returns the recorded substrate (bit-identical
///    chit / gamma_AB observables).
/// 3. Every `(substrate, tau)` from the substrate_grid hits via
///    `lookup_inverse` and returns the recorded canonical (bit-identical
///    chit / gamma_AB / k_frust).
///
/// A successful run closes the BLOCK_IN §v6 session-9-open
/// "InverseLookupSidecar wire format" question: mpa-conform's curator
/// path is now writing to a frozen spec.
#[test]
fn sidecar_python_to_rust_parity() {
    let fixture = load_fixture();
    let cases = fixture["sidecar_wire_format"]
        .as_array()
        .expect("sidecar_wire_format array");
    assert!(
        !cases.is_empty(),
        "sidecar_wire_format fixture must be non-empty",
    );

    for case in cases {
        let label = case["label"].as_str().unwrap_or("<unlabeled>");

        // Deserialize the encoded sidecar via serde — the consumer
        // surface mpa-conform's curator path will write to.
        let sidecar: InverseLookupSidecar = serde_json::from_value(case["sidecar"].clone())
            .unwrap_or_else(|e| panic!("{label}: sidecar deserialize failed: {e}"));

        // ---- (1) structural metadata -----------------------------------
        assert_eq!(
            sidecar.wire_version, "1.0",
            "{label}: wire_version must be 1.0 per current spec",
        );
        assert_eq!(
            sidecar.rounding_decimals, DEFAULT_ROUNDING_DECIMALS,
            "{label}: rounding_decimals default mismatch",
        );
        assert!(
            !sidecar.driver_profile_id.is_empty(),
            "{label}: driver_profile_id must be non-empty",
        );
        assert_eq!(
            sidecar.tau_obs_grid.len(),
            sidecar.canonical_grid.len(),
            "{label}: tau_obs_grid and canonical_grid lengths must match",
        );
        assert_eq!(
            sidecar.tau_obs_grid.len(),
            sidecar.substrate_grid.len(),
            "{label}: tau_obs_grid and substrate_grid lengths must match",
        );
        assert_eq!(
            sidecar.forward_lookup.len(),
            sidecar.tau_obs_grid.len(),
            "{label}: forward_lookup must have one entry per grid frame",
        );
        assert_eq!(
            sidecar.inverse_lookup.len(),
            sidecar.tau_obs_grid.len(),
            "{label}: inverse_lookup must have one entry per grid frame",
        );

        // ---- (2) forward lookup hits ----------------------------------
        for (i, tau) in sidecar.tau_obs_grid.iter().enumerate() {
            let canonical = sidecar.canonical_grid[i].clone();
            let expected_substrate = &sidecar.substrate_grid[i];
            let hit = lookup_forward(&sidecar, &canonical, *tau, sidecar.rounding_decimals)
                .unwrap_or_else(|| {
                    panic!(
                        "{label}: lookup_forward miss at frame {i} \
                         (canonical={canonical:?}, tau={tau})",
                    )
                });
            // Substrate observables must include the canonical pair
            // names; their values must agree bit-for-bit with what the
            // producer recorded (`BanachSubstrate.substrate_at` emits
            // identity-translated substrates: substrate_chit == chit,
            // substrate_gamma_AB == gamma_AB).
            let got_chit = hit
                .observables
                .get("substrate_chit")
                .copied()
                .expect("substrate_chit on hit");
            let got_gamma = hit
                .observables
                .get("substrate_gamma_AB")
                .copied()
                .expect("substrate_gamma_AB on hit");
            let want_chit = expected_substrate
                .observables
                .get("substrate_chit")
                .copied()
                .expect("substrate_chit on expected");
            let want_gamma = expected_substrate
                .observables
                .get("substrate_gamma_AB")
                .copied()
                .expect("substrate_gamma_AB on expected");
            assert_eq!(
                got_chit.to_bits(),
                want_chit.to_bits(),
                "{label}: forward lookup substrate_chit at frame {i}",
            );
            assert_eq!(
                got_gamma.to_bits(),
                want_gamma.to_bits(),
                "{label}: forward lookup substrate_gamma_AB at frame {i}",
            );
        }

        // ---- (3) inverse lookup hits ----------------------------------
        for (i, tau) in sidecar.tau_obs_grid.iter().enumerate() {
            let substrate = &sidecar.substrate_grid[i];
            let expected_canonical = &sidecar.canonical_grid[i];
            let hit = lookup_inverse(&sidecar, substrate, *tau, sidecar.rounding_decimals)
                .unwrap_or_else(|| {
                    panic!(
                        "{label}: lookup_inverse miss at frame {i} \
                         (substrate observables={:?}, tau={tau})",
                        substrate.observables,
                    )
                });
            assert_eq!(
                hit.chit.to_bits(),
                expected_canonical.chit.to_bits(),
                "{label}: inverse lookup chit at frame {i}",
            );
            assert_eq!(
                hit.gamma_AB.to_bits(),
                expected_canonical.gamma_AB.to_bits(),
                "{label}: inverse lookup gamma_AB at frame {i}",
            );
            assert_eq!(
                hit.k_frust, expected_canonical.k_frust,
                "{label}: inverse lookup k_frust at frame {i}",
            );
        }

        // ---- bonus: round_key bit-identity --------------------------
        // The producer rounded with Python `float(np.rint(x*10**n))/10**n`;
        // Rust here rounds with `(x*10^n).round_ties_even()/10^n`. Both
        // produce identical f64 bits for every finite input. Spot-check
        // by re-rounding the first canonical and confirming it matches
        // what's stored in the lookup map's keys.
        let c0 = sidecar.canonical_grid[0].clone();
        let tau0 = sidecar.tau_obs_grid[0];
        let (rc, rg, rt) = round_key(c0.chit, c0.gamma_AB, tau0, sidecar.rounding_decimals);
        // The hit we obtained from lookup_forward used the exact same
        // rounding — if Python and Rust disagreed on rounding for this
        // input, the lookup_forward call above would have missed.
        // Verify the round_key output is at least finite + matches the
        // unrounded values to within the rounding precision.
        assert!(rc.is_finite() && rg.is_finite() && rt.is_finite());
    }
}
